dict(tmdb_id=949, title='Heat', year=1995, genre='Action', director='Michael Mann', cast=['Al Pacino', 'Robert De Niro', 'Val Kilmer'], avg_rating=7.9, poster_url='https://image.tmdb.org/t/p/w500/umSVjVdbVwtx5ryCA2QXL44Durm.jpg', description='Obsessive master thief Neil McCauley leads a top-notch crew on various daring heists throughout Los Angeles while determined detective Vincent Hanna pursues him without rest. Each man recognizes and respects the ability and the dedication of the other even though they are aware their cat-and-mouse game may end in violence.'),
