    dict(tmdb_id=49026, title='The Dark Knight Rises', year=2012, genre='Action', director='Christopher Nolan', cast=['Christian Bale', 'Gary Oldman', 'Tom Hardy'], avg_rating=7.8, poster_url='https://image.tmdb.org/t/p/w500/hr0L2aueqlP2BYUblTTjmtn0hw4.jpg', description="Following the death of District Attorney Harvey Dent, Batman assumes responsibility for Dent's crimes to protect the late attorney's reputation and is subsequently hunted by the Gotham City Police Department. Eight years later, Batman encounters the mysterious Selina Kyle and the villainous Bane, a new terrorist leader who overwhelms Gotham's finest. The Dark Knight resurfaces to protect a city that has branded him an enemy."),
