    dict(tmdb_id=22, title='Pirates of the Caribbean: The Curse of the Black Pearl', year=2003, genre='Adventure', director='Gore Verbinski', cast=['Johnny Depp', 'Geoffrey Rush', 'Orlando Bloom'], avg_rating=7.8, poster_url='https://image.tmdb.org/t/p/w500/poHwCZeWzJCShH7tOjg8RIoyjcw.jpg', description="When wily Captain Barbossa steals Jack Sparrow's ship and kidnaps the governor's beautiful daughter, Elizabeth, her childhood friend Will Turner joins forces with Jack to save her and recapture Jack's ship, the Black Pearl."),
