    dict(tmdb_id=19995, title='Avatar', year=2009, genre='Adventure', director='James Cameron', cast=['Sam Worthington', 'Zoe Saldaña', 'Sigourney Weaver'], avg_rating=7.6, poster_url='https://image.tmdb.org/t/p/w500/gKY6q7SjCkAU6FqvqWybDYgUKIF.jpg', description='In the 22nd century, a paraplegic Marine is dispatched to the moon Pandora on a unique mission, but becomes torn between following orders and protecting an alien civilization.'),
