    dict(tmdb_id=12, title='Finding Nemo', year=2003, genre='Adventure', director='Andrew Stanton', cast=['Albert Brooks', 'Ellen DeGeneres', 'Alexander Gould'], avg_rating=7.8, poster_url='https://image.tmdb.org/t/p/w500/eHuGQ10FUzK1mdOY69wF5pGgEf5.jpg', description="Nemo, an adventurous young clownfish, is unexpectedly taken from his Great Barrier Reef home to a dentist's office aquarium. It's up to his worrisome father Marlin and a friendly but forgetful fish Dory to bring Nemo home -- meeting vegetarian sharks, surfer dude turtles, hypnotic jellyfish, hungry seagulls, and more along the way.", is_animated=True),
